import{_ as t,o as h,c as a,ag as i}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"Sprint 6: Đặt chỗ & Thanh toán (Triển khai)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/01-yeu-cau-nghiep-vu.md","filePath":"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/01-yeu-cau-nghiep-vu.md"}'),o={name:"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/01-yeu-cau-nghiep-vu.md"};function c(r,n,e,l,g,u){return h(),a("div",null,[...n[0]||(n[0]=[i('<h1 id="sprint-6-đat-cho-thanh-toan-trien-khai" tabindex="-1">Sprint 6: Đặt chỗ &amp; Thanh toán (Triển khai) <a class="header-anchor" href="#sprint-6-đat-cho-thanh-toan-trien-khai" aria-label="Permalink to &quot;Sprint 6: Đặt chỗ &amp; Thanh toán (Triển khai)&quot;">​</a></h1><blockquote><p>⚠️ Tài liệu này được viết khi sprint còn là &quot;Sprint 4&quot;. Đã đổi số thành Sprint 6 (xem <code>../trang-thai-web.md</code>). Một số chi tiết về cấu trúc dữ liệu sẽ được rà soát lại ở task <strong>S4-07</strong> (Sprint 4 Đổi nền — đồng bộ tài liệu) — chưa nên dùng làm nguồn sự thật cho code mới cho tới khi rà soát xong.</p></blockquote><p>Sprint này tập trung vào việc làm luồng thanh toán an toàn và tích hợp các cổng thanh toán (VNPay, MoMo).</p><h2 id="_1-pham-vi-lien-ket-nghiep-vu" tabindex="-1">1. Phạm vi &amp; Liên kết nghiệp vụ <a class="header-anchor" href="#_1-pham-vi-lien-ket-nghiep-vu" aria-label="Permalink to &quot;1. Phạm vi &amp; Liên kết nghiệp vụ&quot;">​</a></h2><blockquote><p>Tài liệu yêu cầu sản phẩm gốc đã chuyển vào kho lưu trữ (cấu trúc mới xem <a href="./../../01-nghiep-vu/04-ma-tran-tinh-nang">Ma trận tính năng</a>).</p></blockquote><p>Các tính năng triển khai trong Sprint này được đặc tả chi tiết tại Product Backlog:</p><ul><li><a href="./../../99-tham-khao/archive/03-kho-tinh-nang/dat-cho-thanh-toan/admin-oms">Hành vi Admin: Quản lý Đơn hàng (OMS)</a> (đã lưu trữ)</li><li><a href="./../../99-tham-khao/archive/03-kho-tinh-nang/dat-cho-thanh-toan/client-checkout">Hành vi Client: Luồng Checkout</a> (đã lưu trữ)</li></ul><h2 id="_2-acceptance-criteria-ac-tieu-chi-nghiem-thu" tabindex="-1">2. Acceptance Criteria (AC) - Tiêu chí nghiệm thu <a class="header-anchor" href="#_2-acceptance-criteria-ac-tieu-chi-nghiem-thu" aria-label="Permalink to &quot;2. Acceptance Criteria (AC) - Tiêu chí nghiệm thu&quot;">​</a></h2><h3 id="task-4-1-luong-checkout-3-buoc" tabindex="-1">Task 4.1: Luồng Checkout 3 bước <a class="header-anchor" href="#task-4-1-luong-checkout-3-buoc" aria-label="Permalink to &quot;Task 4.1: Luồng Checkout 3 bước&quot;">​</a></h3><ul><li><strong>AC1</strong>: Người dùng có thể chọn Ngày khởi hành và số lượng hành khách (Người lớn/Trẻ em).</li><li><strong>AC2</strong>: Tự động tính toán Tổng tiền (Total Price) dựa trên bảng giá và số lượng hành khách.</li><li><strong>AC3</strong>: Voucher được áp dụng ngay lập tức và hiển thị số tiền trừ trực tiếp trên màn hình Checkout.</li></ul><h3 id="task-4-2-tich-hop-thanh-toan-vnpay-momo" tabindex="-1">Task 4.2: Tích hợp Thanh toán (VNPay/MoMo) <a class="header-anchor" href="#task-4-2-tich-hop-thanh-toan-vnpay-momo" aria-label="Permalink to &quot;Task 4.2: Tích hợp Thanh toán (VNPay/MoMo)&quot;">​</a></h3><ul><li><strong>AC1</strong>: Redirect thành công sang trang thanh toán của VNPay/MoMo.</li><li><strong>AC2</strong>: Webhook (IPN) xử lý chính xác trạng thái thanh toán từ cổng trả về để cập nhật trạng thái Đơn hàng sang &quot;Paid&quot;.</li><li><strong>AC3</strong>: Xử lý trường hợp người dùng hủy thanh toán (User Cancel) bằng cách quay lại trang thanh toán nhưng vẫn giữ nguyên thông tin đơn hàng.</li></ul><h3 id="task-4-3-quan-ly-trang-thai-đon-hang-order-state-machine" tabindex="-1">Task 4.3: Quản lý trạng thái Đơn hàng (Order State Machine) <a class="header-anchor" href="#task-4-3-quan-ly-trang-thai-đon-hang-order-state-machine" aria-label="Permalink to &quot;Task 4.3: Quản lý trạng thái Đơn hàng (Order State Machine)&quot;">​</a></h3><ul><li><strong>AC1</strong>: Đơn hàng tự động chuyển sang &quot;Cancelled&quot; sau 15 phút nếu chưa thanh toán (Cron Job).</li><li><strong>AC2</strong>: Admin có thể cập nhật trạng thái thủ công (Confirm/Reject) kèm ghi chú cho khách hàng.</li></ul><hr><p><em>Ghi chú: Lịch trình chi tiết và Task phân rã nằm trong <a href="./../backlog-chi-tiet">Backlog chi tiết</a>.</em></p>',16)])])}const k=t(o,[["render",c]]);export{p as __pageData,k as default};
